package io.micrometer.core.instrument.binder.http.servicemesh;

package dev.langchain4j.model.ollama;

import static org.assertj.core.api.Assertions.assertThat;

import org.junit.jupiter.api.Test;

class RunningOllamaModelTest {

    @Test
    void should_deserialize_context_length() {
        // given - JSON matching Ollama PS API response including context_length field
        String json = "{\"name\":\"llama3:latest\",\"model\":\"llama3:latest\",\"size\":123456," +
                "\"digest\":\"abc123\",\"details\":{\"family\":\"llama\",\"parameter_size\":\"8B\"," +
                "\"quantization_level\":\"Q4_0\"},\"expires_at\":\"2026-05-29T10:00:00+00:00\"," +
                "\"size_vram\":1024,\"context_length\":4096}";

        // when
        RunningOllamaModel model = OllamaJsonUtils.getObjectMapper().readValue(json, RunningOllamaModel.class);

        // then
        assertThat(model.getContextLength()).isEqualTo(4096);
    }

    @Test
    void should_serialize_context_length() throws Exception {
        // given
        RunningOllamaModel model = RunningOllamaModel.builder()
                .name("llama3:latest")
                .model("llama3:latest")
                .size(123456L)
                .digest("abc123")
                .details(new OllamaModelDetails("llama", "llama", null, null, null, null))
                .expiresAt(java.time.OffsetDateTime.parse("2026-05-29T10:00:00+00:00"))
                .sizeVram(1024L)
                .contextLength(4096) // this is the new field
                .build();

        // when
        String json = OllamaJsonUtils.getObjectMapper().writeValueAsString(model);

        // then
        assertThat(json).contains("\"context_length\":4096");
    }
}

